INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06940', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '調查研究中，當面訪問、電話訪問、郵寄問卷與線上調查（網路填答）的優缺點，下列敘述何者錯誤？', '["當面訪問，受訪者會比較配合，回收率高，也比較不會出現社會期望性的答案", "電話訪問問卷完成速度快，但受詐騙電話肆虐的影響，拒訪率高", "郵寄問卷成本低，但回收率低，也無法確定是否由他人代填問卷", "線上調查的缺點是較難確保樣本的代表性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06941', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對「內容分析（content analysis）」的敘述，何者正確﹖', '["它並不適用於誰向誰說了什麼、為何說、如何說、產生什麼效果的傳播研究", "為了編碼具有信度，它重視溝通中隱性的內容（latent content）", "內容分析可以是計量的，也可以是計質的研究", "為了編碼具有效度，內容分析的缺點在不易重複再做一次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06942', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對焦點團體（focus group）的敘述，何者正確﹖', '["參與焦點團體的成員，可以依據討論主題的關聯性，以立意抽樣方式選出", "考量資料信度，焦點團體蒐集資料的次數以一次為佳", "焦點團體所蒐集的資料，因為人多而具有系統性，不易受到參與者偏誤影響", "考量資料效度，焦點團體蒐集資料的次數以一次為佳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06943', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某位採用質性觀察的研究者，坐在校園操場邊，觀察學生下課時的互動。此時，他採取的研究角色是﹕', '["完全參與者", "觀察參與者", "參與觀察者", "完全觀察者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06944', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列「需求評估（needs assessment）」方法的組合，何者正確？①調查關鍵資訊提供者  ②舉行社區論', '["檢視接受處遇者比例", "分析社會指標  ⑤進行社區或目標團體調查", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06945', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對「演繹法（deduction）」的敘述，何者正確？', '["它是種從普遍性推論到特殊結論的邏輯模型", "它是種從個別觀察衍生到普遍結論的過程", "多數質化研究偏向採用它", "紮根理論（grounded theory）就是這種方法的應用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06946', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某位慣用家庭溝通動態分析並解釋問題的社工，容易留意家庭中潛在的溝通問題，並放大其對整體事件 的影響力。請問他犯了下列何種錯誤？', '["稻草人論證（straw person）", "選擇性觀察（selective observation）", "人身攻擊（ad hominem attack）", "事後假設（ex post facto hypothesizing）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06947', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社會工作研究者想了解安置兒童返家後的適應，包括安置經驗對他的影響、親子關係的重建、對生活 環境變化的適應等，以對兒童安置處遇提出建議。此研究較適合採用的典範是：', '["實證主義（positivism）", "解析主義（interpretivism）", "批判主義（criticism）", "絕對主義（absolutism）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06948', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列關於質化研究與量化研究的敘述，何者正確？', '["質化是演繹的邏輯；量化是歸納的邏輯", "質化方法常用於解釋性研究；量化方法則較常用於探索性研究", "兩種研究方法都是有系統和可驗證的", "兩種研究方法都強調儘可能的隨機抽樣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06949', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究發現，新住民子女發展遲緩的比例較非新住民子女高，但是加入另一個變項「家庭社經地位」之 後，差異就不顯著了。下列關於三個變項的敘述，何者錯誤？', '["「新住民子女」與「發展遲緩」兩個變項是虛假關係", "「家庭社經地位」是中介變項，透過它的作用，「新住民子女」才會對「發展遲緩」產生作用", "新住民子女之所以呈現較高比例發展遲緩，是因為他們有較高比例家庭社經地位較低", "「家庭社經地位」變項與「新住民子女」、「發展遲緩」兩個變項相關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
